solution: class Solution {
public:
    int numWays(int steps, int arrLen) {
        const int MOD = 1'000'000'007;
        int maxPos = min(steps / 2 + 1, arrLen);
        vector<int> dp(maxPos, 0);
        dp[0] = 1;
        for (int s = 1; s <= steps; ++s) {
            vector<int> next(maxPos, 0);
            for (int p = 0; p < maxPos; ++p) {
                next[p] = dp[p];
                if (p > 0) next[p] = (next[p] + dp[p - 1]) % MOD;
                if (p + 1 < maxPos) next[p] = (next[p] + dp[p + 1]) % MOD;
            }
            dp = move(next);
        }
        return dp[0];
    }
};
